import os
from datetime import datetime
from docx import Document
from docx.shared import Pt
from docx.enum.text import WD_ALIGN_PARAGRAPH
import re

def convert_md_to_docx(md_path, docx_path):
    doc = Document()

    # Professional Styling: Set default font
    style = doc.styles['Normal']
    font = style.font
    font.name = 'Calibri'
    font.size = Pt(11)

    with open(md_path, 'r', encoding='utf-8') as f:
        lines = f.readlines()

    title_found = False
    for line in lines:
        line = line.strip()
        if not line:
            continue

        # Heading 1
        if line.startswith('# '):
            heading = line[2:]
            if not title_found:
                # First # is treated as Title
                p = doc.add_heading(heading, 0)
                p.alignment = WD_ALIGN_PARAGRAPH.CENTER
                title_found = True
            else:
                doc.add_heading(heading, level=1)
        # Heading 2
        elif line.startswith('## '):
            doc.add_heading(line[3:], level=2)
        # Heading 3
        elif line.startswith('### '):
            doc.add_heading(line[4:], level=3)
        # Lists
        elif line.startswith('- ') or line.startswith('* '):
            doc.add_paragraph(line[2:], style='List Bullet')
        elif re.match(r'^\d+\. ', line):
            doc.add_paragraph(re.sub(r'^\d+\. ', '', line), style='List Number')
        # Bold and Italic (Basic support)
        else:
            p = doc.add_paragraph()
            # Split by bold markers **
            parts = re.split(r'(\*\*.*?\*\*)', line)
            for part in parts:
                if part.startswith('**') and part.endswith('**'):
                    run = p.add_run(part[2:-2])
                    run.bold = True
                else:
                    # Further split by italic markers *
                    subparts = re.split(r'(\*.*?\*)', part)
                    for subpart in subparts:
                        if subpart.startswith('*') and subpart.endswith('*'):
                            run = p.add_run(subpart[1:-1])
                            run.italic = True
                        else:
                            p.add_run(subpart)

    doc.save(docx_path)
    print(f"Converted: {md_path} -> {docx_path}")

def main():
    docs_dir = 'docs'
    target_date = datetime(2026, 4, 6).date()

    files_to_convert = []
    for filename in os.listdir(docs_dir):
        if filename.endswith('.md'):
            filepath = os.path.join(docs_dir, filename)
            mtime = datetime.fromtimestamp(os.path.getmtime(filepath)).date()
            if mtime == target_date:
                files_to_convert.append(filename)

    if not files_to_convert:
        print("No files found for the specified date.")
        return

    for filename in files_to_convert:
        md_path = os.path.join(docs_dir, filename)
        docx_path = os.path.join(docs_dir, filename.replace('.md', '.docx'))
        convert_md_to_docx(md_path, docx_path)

if __name__ == "__main__":
    main()

