    """Bridge between Gradio file-upload and engine.load_graph(path, emb_type)."""
    if file_obj is not None:
        path = file_obj.name
    elif csv_path_text and csv_path_text.strip():
        path = csv_path_text.strip()
    else:
        return "ERROR: No file provided.", "N/A"

